use anyhow::{Context, Result};
use csv::Writer;
use crate::db;

pub fn run(output: &str, table: &str) -> Result<()> {
    let conn = db::connect()?;
    let mut stmt = conn.prepare(&format!("SELECT * FROM {}", table))
        .with_context(|| format!("Table '{}' not found", table))?;
    let col_count = stmt.column_count();
    let columns: Vec<String> = (0..col_count)
        .map(|i| stmt.column_name(i).unwrap().to_string())
        .collect();

    let mut wtr = Writer::from_path(output)
        .with_context(|| format!("Cannot write to {}", output))?;
    wtr.write_record(&columns)?;

    let mut rows = stmt.query([])?;
    while let Some(row) = rows.next()? {
        let values: Vec<String> = (0..col_count)
            .map(|i| row.get::<_, String>(i).unwrap_or_default())
            .collect();
        wtr.write_record(&values)?;
    }
    wtr.flush()?;
    println!("Exported to {}", output);
    Ok(())
}

use clap::{Parser, Subcommand};
use anyhow::Result;

mod db;
mod import;
mod export;

#[derive(Parser)]
#[command(name = "data-tool")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    Import { file: String },
    Export {
        /// Output CSV file path
        output: String,
        /// Table to export
        #[arg(short, long, default_value = "data")]
        table: String,
    },
}

fn main() -> Result<()> {
    let cli = Cli::parse();
    match cli.command {
        Commands::Import { file } => import::run(&file),
        Commands::Export { output, table } => export::run(&output, &table),
    }
}
